1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const INSURANCE_VALUE: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	  rune: 250,
19	  moonstone: 250,
20	};
21	
22	const CURSE_SURCHARGE = 0.5;
23	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_DISCOUNT = 0.2;
26	const LOYALTY_THRESHOLD_YEARS = 2;
27	const FOLLOW_UP_DISCOUNT = 0.15;
28	const DEDUCTIBLE = 100;
29	const CAP_MULTIPLIER = 2;
30	
31	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
32	type Damage = { itemType: string; amount: number };
33	type Incident = { cause: string; damages: Damage[] };
34	type QuoteStep = { op: "quote"; items: Item[] };
35	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
36	type Step = QuoteStep | ClaimStep;
37	type Customer = { yearsWithMHPCO: number };
38	type Scenario = { customer: Customer; steps: Step[] };
39	type QuoteResult = { premium: number };
40	type ClaimResult = { payout: number; remainingCap: number };
41	type StepResult = QuoteResult | ClaimResult;
42	
43	// MHPCO rounds premiums up in its own favor. A float-precision guard avoids
44	// surprises like 197.5 + 0 rendering as 197.5000000001 and rounding to 198
45	// when the true mathematical value was already on an integer boundary.
46	const roundUpInMHPCOFavor = (amount: number): number =>
47	  Math.ceil(Math.round(amount * 1e6) / 1e6);
48	
49	const roundDownInMHPCOFavor = (amount: number): number =>
50	  Math.floor(Math.round(amount * 1e6) / 1e6);
51	
52	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
53	const COMPONENT_BLOCK_SIZE = 3;
54	const COMPONENT_BLOCK_PREMIUM = 60;
55	
56	const componentGroupPremium = (type: string, count: number): number =>
57	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * BASE_PREMIUM[type];
58	
59	type PremiumLine = { base: number; itemSurchargeRate: number };
60	
61	const mainItemSurchargeRate = (item: Item): number => {
62	  let rate = 0;
63	  if (item.cursed) rate += CURSE_SURCHARGE;
64	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE;
65	  return rate;
66	};
67	
68	const mainItemLine = (item: Item): PremiumLine => {
69	  const base = BASE_PREMIUM[item.type];
70	  if (base === undefined) {
71	    throw new Error(`Unknown item type: ${item.type}`);
72	  }
73	  return { base, itemSurchargeRate: mainItemSurchargeRate(item) };
74	};
75	
76	const itemPremiumLines = (items: Item[]): PremiumLine[] => {
77	  const mainItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
78	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
79	  const componentCountsByType = new Map<string, number>();
80	  for (const c of components) {
81	    componentCountsByType.set(c.type, (componentCountsByType.get(c.type) ?? 0) + 1);
82	  }
83	  const mainLines = mainItems.map(mainItemLine);
84	  const componentLines = [...componentCountsByType].map(([type, count]) => ({
85	    base: componentGroupPremium(type, count),
86	    itemSurchargeRate: 0,
87	  }));
88	  return [...mainLines, ...componentLines];
89	};
90	
91	const linePremium = (line: PremiumLine): number =>
92	  line.base * (1 + FIRST_INSURANCE_SURCHARGE + line.itemSurchargeRate);
93	
94	const policyWideRate = (customer: Customer, quoteIndex: number): number => {
95	  let rate = 0;
96	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
97	  if (quoteIndex > 0) rate -= FOLLOW_UP_DISCOUNT;
98	  return rate;
99	};
100	
101	const computePremium = (step: QuoteStep, customer: Customer, quoteIndex: number): number => {
102	  const lines = itemPremiumLines(step.items);
103	  const itemSurchargeTotal = lines.map(linePremium).reduce((sum, p) => sum + p, 0);
104	  const policyBase = lines.reduce((sum, l) => sum + l.base, 0);
105	  const total = itemSurchargeTotal + policyBase * policyWideRate(customer, quoteIndex) + PROCESSING_FEE;
106	  return roundUpInMHPCOFavor(total);
107	};
108	
109	type Policy = { items: Item[]; cap: number };
110	
111	const createPolicy = (items: Item[]): Policy => {
112	  const insuranceSum = items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
113	  return { items, cap: insuranceSum * CAP_MULTIPLIER };
114	};
115	
116	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
117	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
118	
119	const damagePayout = (damage: Damage, item: Item): number => {
120	  const reimbursementRate = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
121	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
122	    : 1;
123	  return Math.max(0, damage.amount * reimbursementRate - DEDUCTIBLE);
124	};
125	
126	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
127	  const policy = policies[step.policy];
128	  const totalDamage = step.incident.damages.reduce((sum, d) => {
129	    const item = policy.items.find((i) => i.type === d.itemType)!;
130	    return sum + damagePayout(d, item);
131	  }, 0);
132	  const payout = roundDownInMHPCOFavor(totalDamage);
133	  policy.cap -= payout;
134	  return { payout, remainingCap: policy.cap };
135	};
136	
137	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
138	  const policies: Policy[] = [];
139	  const results: StepResult[] = scenario.steps.map((step) => {
140	    if (step.op === "quote") {
141	      const premium = computePremium(step, scenario.customer, policies.length);
142	      policies.push(createPolicy(step.items));
143	      return { premium };
144	    }
145	    return processClaim(step, policies);
146	  });
147	  return { results };
148	};
